        let sanitizedCallbackId = callbackId.replacingOccurrences(of: "'", with: "\\'")
        
        var jsonString = "null"
        if let dict = result as? [String: Any],
           let data = try? JSONSerialization.data(withJSONObject: dict),
           let str = String(data: data, encoding: .utf8) {
            jsonString = str
        } else if let str = result as? String {
            jsonString = "\"\(str.replacingOccurrences(of: "\"", with: "\\\""))\""
        } else if let bool = result as? Bool {
            jsonString = bool ? "true" : "false"
        }
        
        let js = "window.NativeBridge._resolveCallback('\(sanitizedCallbackId)', \(jsonString));"
        DispatchQueue.main.async { [weak self] in
            self?.webView.evaluateJavaScript(js, completionHandler: nil)
        }
    }
    
    private func rejectCallback(_ callbackId: String?, error: String) {
        guard let callbackId = callbackId else { return }
        let sanitizedCallbackId = callbackId.replacingOccurrences(of: "'", with: "\\'")
        let sanitizedError = error.replacingOccurrences(of: "'", with: "\\'")
        
