    // MARK: - Native Feature Handlers
    private func handleCameraMessage(_ message: JSMessage) {
        switch message.action {
        case "takePhoto":
            requestCameraAccess { [weak self] granted in
                guard granted else {
                    self?.rejectCallback(message.callbackId, error: "Camera permission denied")
                    return
                }
                DispatchQueue.main.async {
                    self?.presentImagePicker(sourceType: .camera, callbackId: message.callbackId)
                }
            }
            
        case "pickFromLibrary":
            DispatchQueue.main.async { [weak self] in
                self?.presentImagePicker(sourceType: .photoLibrary, callbackId: message.callbackId)
            }
            
        case "checkPermission":
            let status = AVCaptureDevice.authorizationStatus(for: .video)
            let statusString: String
            switch status {
            case .authorized: statusString = "authorized"
            case .denied: statusString = "denied"
            case .restricted: statusString = "restricted"
            case .notDetermined: statusString = "notDetermined"
            @unknown default: statusString = "unknown"
            }
            resolveCallback(message.callbackId, result: ["status": statusString])
            
        default:
            rejectCallback(message.callbackId, error: "Unknown camera action: \(message.action)")
        }
    }
    
    private func handlePushNotificationMessage(_ message: JSMessage) {
        switch message.action {
        case "requestPermission":
            UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
                if let error = error {
                    self?.rejectCallback(message.callbackId, error: error.localizedDescription)
                    return
                }
                
                if granted {
                    DispatchQueue.main.async {
                        UIApplication.shared.registerForRemoteNotifications()
                    }
                }
                
                self?.resolveCallback(message.callbackId, result: ["granted": granted])
            }
            
        case "getToken":
            if let token = deviceToken {
                resolveCallback(message.callbackId, result: ["token": token])
            } else {
                rejectCallback(message.callbackId, error: "Push notification token not available")
            }
            
        case "checkPermission":
            UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
                let statusString: String
                switch settings.authorizationStatus {
                case .authorized: statusString = "authorized"
                case .denied: statusString = "denied"
                case .provisional: statusString = "provisional"
                case .ephemeral: statusString = "ephemeral"
                case .notDetermined: statusString = "notDetermined"
                @unknown default: statusString = "unknown"
                }
                self?.resolveCallback(message.callbackId, result: ["status": statusString])
            }
            
        default:
            rejectCallback(message.callbackId, error: "Unknown push notification action: \(message.action)")
        }
    }
    
    private func handleInAppPurchaseMessage(_ message: JSMessage) {
        switch message.action {
        case "getProducts":
            guard let productIds = message.payload["productIds"] as? [String], !productIds.isEmpty else {
                rejectCallback(message.callbackId, error: "No product IDs provided")
                return
            }
            
            iapManager?.fetchProducts(productIds: Set(productIds)) { [weak self] result in
                switch result {
                case .success(let products):
                    let productDicts = products.map { product -> [String: Any] in
                        return [
                            "id": product.productIdentifier,
                            "title": product.localizedTitle,
                            "description": product.localizedDescription,
                            "price": product.price.doubleValue,
                            "priceLocale": product.priceLocale.identifier,
                            "formattedPrice": NumberFormatter.localizedString(from: product.price, number: .currency)
                        ]
                    }
                    self?.resolveCallback(message.callbackId, result: ["products": productDicts])
                    
                case .failure(let error):
                    self?.rejectCallback(message.callbackId, error: error.localizedDescription)
                }
            }
            
        case "purchase":
            guard let productId = message.payload["productId"] as? String else {
                rejectCallback(message.callbackId, error: "No product ID provided")
                return
            }
            
            iapManager?.purchase(productId: productId) { [weak self] result in
                switch result {
                case .success(let transactionId):
                    self?.resolveCallback(message.callbackId, result: [
                        "success": true,
                        "transactionId": transactionId
                    ])
                case .failure(let error):
                    self?.rejectCallback(message.callbackId, error: error.localizedDescription)
                }
            }
            
        case "restorePurchases":
            iapManager?.restorePurchases { [weak self] result in
                switch result {
                case .success(let restoredIds):
                    self?.resolveCallback(message.callbackId, result: ["restoredProductIds": restoredIds])
                case .failure(let error):
                    self?.rejectCallback(message.callbackId, error: error.localizedDescription)
                }
            }
            
        default:
            rejectCallback(message.callbackId, error: "Unknown IAP action: \(message.action)")
        }
    }
    
    private func handleHapticFeedback(_ message: JSMessage) {
        switch message.action {
        case "impact":
            let style: UIImpactFeedbackGenerator.FeedbackStyle
            switch message.payload["style"] as? String {
            case "light": style = .light
            case "heavy": style = .heavy
            case "rigid": style = .rigid
            case "soft": style = .soft
            default: style = .medium
            }
            let generator = UIImpactFeedbackGenerator(style: style)
            generator.prepare()
            generator.impactOccurred()
            resolveCallback(message.callbackId, result: ["success": true])
            
        case "notification":
            let type: UINotificationFeedbackGenerator.FeedbackType
            switch message.payload["type"] as? String {
            case "error": type = .error
            case "warning": type = .warning
            default: type = .success
            }
            let generator = UINotificationFeedbackGenerator()
            generator.prepare()
            generator.notificationOccurred(type)
            resolveCallback(message.callbackId, result: ["success": true])
            
        default:
            rejectCallback(message.callbackId, error: "Unknown haptic action: \(message.action)")
        }
    }
    
    private func handleNativeLog(_ message: JSMessage) {
        let level = message.payload["level"] as? String ?? "info"
        let logMessage = message.payload["message"] as? String ?? ""
        
        #if DEBUG
        print("[\(level.uppercased())] WebApp: \(logMessage)")
        #endif
        
        resolveCallback(message.callbackId, result: ["logged": true])
    }
    
    // MARK: - Camera Helpers
    private func requestCameraAccess(completion: @escaping (Bool) -> Void) {
        switch AVCaptureDevice.authorizationStatus(for: .video) {
        case .authorized:
            completion(true)
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { granted in
                completion(granted)
            }
        default:
            completion(false)
        }
    }
    
    private var pendingImageCallbackId: String?
    
    private func presentImagePicker(sourceType: UIImagePickerController.SourceType, callbackId: String?) {
        guard UIImagePickerController.isSourceTypeAvailable(sourceType) else {
            rejectCallback(callbackId, error: "Source type not available")
            return
        }
        
        pendingImageCallbackId = callbackId
        
        let picker = UIImagePickerController()
        picker.sourceType = sourceType
        picker.delegate = self
        picker.allowsEditing = true
        present(picker, animated: true)
    }
    
