// MARK: - WKScriptMessageHandler
extension HybridWebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let handler = JSMessageHandler(rawValue: message.name) else {
            print("Unknown message handler: \(message.name)")
            return
        }
        
        guard let jsMessage = JSMessage(from: message.body) else {
            print("Invalid message format from handler: \(message.name)")
            return
        }
        
        // Verify the message origin
        guard let url = message.frameInfo.request.url,
              SecureWebViewConfiguration.isAllowedURL(url) || message.frameInfo.isMainFrame else {
            print("Blocked message from unauthorized origin: \(message.frameInfo.request.url?.absoluteString ?? "unknown")")
            rejectCallback(jsMessage.callbackId, error: "Unauthorized origin")
            return
        }
        
        switch handler {
        case .camera:
            handleCameraMessage(jsMessage)
        case .pushNotification:
            handlePushNotificationMessage(jsMessage)
        case .inAppPurchase:
            handleInAppPurchaseMessage(jsMessage)
        case .hapticFeedback:
            handleHapticFeedback(jsMessage)
        case .nativeLog:
            handleNativeLog(jsMessage)
        }
    }
}

// MARK: - WKNavigationDelegate
extension HybridWebViewController: WKNavigationDelegate {
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        // Allow about:blank
        if url.absoluteString == "about:blank" {
            decisionHandler(.allow)
            return
        }
        
        // Block non-HTTPS requests
        guard let scheme = url.scheme?.lowercased(), scheme == "https" else {
            print("Blocked non-HTTPS navigation: \(url.absoluteString)")
            decisionHandler(.cancel)
            return
        }
        
        // Check if URL is in allowed hosts
        if SecureWebViewConfiguration.isAllowedURL(url) {
            decisionHandler(.allow)
            return
        }
        
        // For external links, open in Safari
        if navigationAction.navigationType == .linkActivated {
            UIApplication.shared.open(url)
            decisionHandler(.cancel)
            return
        }
        
        // Block all other navigations to unauthorized domains
        print("Blocked navigation to unauthorized URL: \(url.absoluteString)")
        decisionHandler(.cancel)
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationResponse: WKNavigationResponse, decisionHandler: @escaping (WKNavigationResponsePolicy) -> Void) {
        guard let httpResponse = navigationResponse.response as? HTTPURLResponse else {
            decisionHandler(.allow)
            return
        }
        
        // Validate SSL/TLS - reject if status indicates server error
        if httpResponse.statusCode >= 400 {
            print("HTTP error: \(httpResponse.statusCode)")
        }
        
        decisionHandler(.allow)
    }
    
    func webView(_ webView: WKWebView, didStartProvisionalNavigation navigation: WKNavigation!) {
        activityIndicator.startAnimating()
        errorView.isHidden = true
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        activityIndicator.stopAnimating()
        errorView.isHidden = true
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
        showError(error)
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
        showError(error)
    }
    
    func webView(_ webView: WKWebView, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Validate the server certificate
        let policies = [SecPolicyCreateSSL(true, challenge.protectionSpace.host as CFString)]
        SecTrustSetPolicies(serverTrust, policies as CFTypeRef)
        
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        if isValid {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else {
            print("SSL certificate validation failed: \(error?.localizedDescription ?? "unknown error")")
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
    
    private func showError(_ error: Error) {
        let nsError = error as NSError
        // Don't show error for cancelled navigations
        guard nsError.code != NSURLErrorCancelled else { return }
        
        errorView.isHidden = false
    }
}

// MARK: - WKUIDelegate
extension HybridWebViewController: WKUIDelegate {
    
    func webView(_ webView: WKWebView, createWebViewWith configuration: WKWebViewConfiguration, for navigationAction: WKNavigationAction, windowFeatures: WKWindowFeatures) -> WKWebView? {
        // Prevent pop-ups; load in same webview if it's a valid URL
        if let url = navigationAction.request.url, SecureWebViewConfiguration.isAllowedURL(url) {
            webView.load(navigationAction.request)
        }
        return nil
    }
    
    func webView(_ webView: WKWebView, runJavaScriptAlertPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping () -> Void) {
        // Verify origin
        guard let url = frame.request.url, SecureWebViewConfiguration.isAllowedURL(url) else {
            completionHandler()
            return
        }
        
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    func webView(_ webView: WKWebView, runJavaScriptConfirmPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (Bool) -> Void) {
        guard let url = frame.request.url, SecureWebViewConfiguration.isAllowedURL(url) else {
            completionHandler(false)
            return
        }
        
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        present(alert, animated: true)
    }
    
    func webView(_ webView: WKWebView, runJavaScriptTextInputPanelWithPrompt prompt: String, defaultText: String?, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (String?) -> Void) {
        guard let url = frame.request.url, SecureWebViewConfiguration.isAllowedURL(url) else {
            completionHandler(nil)
            return
        }
        
        let alert = UIAlertController(title: nil, message: prompt, preferredStyle: .alert)
        alert.addTextField { textField in
            textField.text = defaultText
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(nil)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(alert.textFields?.first?.text)
        })
        present(alert, animated: true)
    }
}

// MARK: - UIImagePickerControllerDelegate
extension HybridWebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey: Any]) {
        picker.dismiss(animated: true)
        
        guard let image = info[.editedImage] as? UIImage ?? info[.originalImage] as? UIImage else {
            rejectCallback(pendingImageCallbackId, error: "Failed to get image")
            pendingImageCallbackId = nil
            return
        }
        
        // Compress and convert to base64
        guard let imageData = image.jpegData(compressionQuality: 0.7) else {
            rejectCallback(pendingImageCallbackId, error: "Failed to process image")
            pendingImageCallbackId = nil
            return
        }
        
        let base64String = imageData.base64EncodedString()
        resolveCallback(pendingImageCallbackId, result: [
            "imageData": "data:image/jpeg;base64,\(base64String)",
            "width": image.size.width,
            "height": image.size.height
        ])
        pendingImageCallbackId = nil
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        picker.dismiss(animated: true)
        rejectCallback(pendingImageCallbackId, error: "User cancelled")
        pendingImageCallbackId = nil
    }
}

// MARK: - LeakAvoider (prevents retain cycle with WKUserContentController)
final class LeakAvoider: NSObject, WKScriptMessageHandler {
    weak var delegate: WKScriptMessageHandler?
    
    init(delegate: WKScriptMessageHandler) {
        self.delegate = delegate
        super.init()
    }
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        delegate?.userContentController(userContentController, didReceive: message)
    }
}

// MARK: - InAppPurchaseManager
final class InAppPurchaseManager: NSObject, SKProductsRequestDelegate, SKPaymentTransactionObserver {
    
    private var products: [String: SKProduct] = [:]
    private var fetchCompletion: ((Result<[SKProduct], Error>) -> Void)?
    private var purchaseCompletion: ((Result<String, Error>) -> Void)?
    private var restoreCompletion: ((Result<[String], Error>) -> Void)?
    private var restoredProductIds: [String] = []
    
    override init() {
        super.init()
        SKPaymentQueue.default().add(self)
    }
    
    deinit {
        SKPaymentQueue.default().remove(self)
    }
    
    func fetchProducts(productIds: Set<String>, completion: @escaping (Result<[SKProduct], Error>) -> Void) {
        fetchCompletion = completion
        let request = SKProductsRequest(productIdentifiers: productIds)
        request.delegate = self
        request.start()
    }
    
    func purchase(productId: String, completion: @escaping (Result<String, Error>) -> Void) {
        guard let product = products[productId] else {
            completion(.failure(NSError(domain: "IAP", code: -1, userInfo: [NSLocalizedDescriptionKey: "Product not found. Fetch products first."])))
            return
        }
        
        guard SKPaymentQueue.canMakePayments() else {
            completion(.failure(NSError(domain: "IAP", code: -2, userInfo: [NSLocalizedDescriptionKey: "In-app purchases are disabled on this device."])))
            return
        }
        
        purchaseCompletion = completion
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }
    
    func restorePurchases(completion: @escaping (Result<[String], Error>) -> Void) {
        restoreCompletion = completion
        restoredProductIds = []
        SKPaymentQueue.default().restoreCompletedTransactions()
    }
    
    // MARK: - SKProductsRequestDelegate
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        for product in response.products {
            products[product.productIdentifier] = product
        }
        
        DispatchQueue.main.async { [weak self] in
            self?.fetchCompletion?(.success(response.products))
            self?.fetchCompletion = nil
        }
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        DispatchQueue.main.async { [weak self] in
            self?.fetchCompletion?(.failure(error))
            self?.fetchCompletion = nil
        }
    }
    
    // MARK: - SKPaymentTransactionObserver
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                let transactionId = transaction.transactionIdentifier ?? "unknown"
                SKPaymentQueue.default().finishTransaction(transaction)
                DispatchQueue.main.async { [weak self] in
                    self?.purchaseCompletion?(.success(transactionId))
                    self?.purchaseCompletion = nil
                }
                
            case .failed:
                SKPaymentQueue.default().finishTransaction(transaction)
                let error = transaction.error ?? NSError(domain: "IAP", code: -3, userInfo: [NSLocalizedDescriptionKey: "Purchase failed"])
                DispatchQueue.main.async { [weak self] in
                    self?.purchaseCompletion?(.failure(error))
                    self?.purchaseCompletion = nil
                }
                
            case .restored:
                restoredProductIds.append(transaction.payment.productIdentifier)
                SKPaymentQueue.default().finishTransaction(transaction)
                
            case .deferred, .purchasing:
                break
                
            @unknown default:
                break
            }
        }
    }
    
    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        DispatchQueue.main.async { [weak self] in
            guard let self = self else { return }
            self.restoreCompletion?(.success(self.restoredProductIds))
            self.restoreCompletion = nil
            self.restoredProductIds = []
        }
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        DispatchQueue.main.async { [weak self] in
            self?.restoreCompletion?(.failure(error))
            self?.restoreCompletion = nil
            self?.restoredProductIds = []
        }
    }
}